@app.route('/login')
def login():
    auth_url = (
        f"{AUTHORIZATION_ENDPOINT}?"
        f"response_type=id_token&"
        f"client_id={CLIENT_ID}&"
        f"redirect_uri={REDIRECT_URI}&"
        f"scope=openid"
    )
    return redirect(auth_url)

@app.route('/callback')
def callback():
    id_token = request.args.get('id_token')
    if not id_token:
        return "No ID token received", 400
    
    # Validate token (basic validation)
    try:
        # In production, validate JWT signature and claims
        # This is a simplified version
        token_parts = id_token.split('.')
        if len(token_parts) != 3:
            return "Invalid token format", 400
        
        # Store token in session
        session['id_token'] = id_token
        return redirect('/dashboard')
    except Exception as e:
        return f"Token validation failed: {str(e)}", 400

@app.route('/dashboard')
def dashboard():
    if 'id_token' not in session:
        return redirect('/login')
    
    return f"Welcome to Admin Dashboard! Token: {session['id_token'][:20]}..."

